package main

import("encoding/json";"fmt";"log";"net/http";"os";"time";"github.com/redis/go-redis/v9")
type item struct{ProductID string `json:"productId"`;Quantity int `json:"quantity"`}
func reply(w http.ResponseWriter,s int,v any){w.Header().Set("Content-Type","application/json");w.WriteHeader(s);_=json.NewEncoder(w).Encode(v)}
func items(c *redis.Client,r *http.Request,key string)[]item{v,_:=c.HGetAll(r.Context(),key).Result();out:=[]item{};for id,raw:=range v{var q int;fmt.Sscan(raw,&q);out=append(out,item{id,q})};return out}
func main(){opt,e:=redis.ParseURL(os.Getenv("REDIS_URL"));if e!=nil{log.Fatal(e)};c:=redis.NewClient(opt);defer c.Close();mux:=http.NewServeMux();mux.HandleFunc("GET /health",func(w http.ResponseWriter,r *http.Request){if c.Ping(r.Context()).Err()!=nil{reply(w,503,map[string]string{"service":"cart","status":"unavailable"});return};reply(w,200,map[string]string{"service":"cart","status":"ok"})});mux.HandleFunc("GET /{id}",func(w http.ResponseWriter,r *http.Request){id:=r.PathValue("id");reply(w,200,map[string]any{"id":id,"items":items(c,r,"cart:"+id)})});mux.HandleFunc("POST /{id}/items",func(w http.ResponseWriter,r *http.Request){var in item;if json.NewDecoder(http.MaxBytesReader(w,r.Body,1<<20)).Decode(&in)!=nil||in.ProductID==""||in.Quantity<1{reply(w,400,map[string]string{"error":"productId_and_positive_quantity_required"});return};id:=r.PathValue("id");key:="cart:"+id;p:=c.TxPipeline();p.HIncrBy(r.Context(),key,in.ProductID,int64(in.Quantity));p.Expire(r.Context(),key,30*24*time.Hour);if _,e:=p.Exec(r.Context());e!=nil{reply(w,500,map[string]string{"error":"cart_write_failed"});return};reply(w,201,map[string]any{"id":id,"items":items(c,r,key)})});port:=os.Getenv("PORT");if port==""{port="4002"};log.Fatal(http.ListenAndServe(":"+port,mux))}
